SELECT MAX("daily_count") FROM (SELECT DATE(TO_TIMESTAMP("start_time", 6)) AS "trip_date", COUNT(*) AS "daily_count" FROM "AUSTIN"."AUSTIN_BIKESHARE"."BIKESHARE_TRIPS" WHERE "bike_type" = 'electric' AND "duration_minutes" > 10 AND "subscriber_type" = 'Student Membership' AND "start_station_name" NOT IN ('Mobile Station', 'Repair Shop') AND "end_station_name" NOT IN ('Mobile Station', 'Repair Shop') GROUP BY "trip_date") AS "daily_counts"